const input = $input.first().json;
const webhookBody = input.body && typeof input.body === 'object' ? input.body : {};
const nestedBody = webhookBody.body && typeof webhookBody.body === 'object' && !Array.isArray(webhookBody.body)
  ? webhookBody.body
  : {};
const responses = Array.isArray(nestedBody.body)
  ? nestedBody.body
  : Array.isArray(webhookBody.body)
    ? webhookBody.body
    : Array.isArray(input.body)
      ? input.body
      : Array.isArray(input.results)
        ? input.results
        : [];

const campaignId = nestedBody.campaign_id || webhookBody.campaign_id || input.campaign_id || input.campaignId || '';
const companyName = webhookBody.company_name || nestedBody.company_name || input.company_name || responses[0]?.Employeur || responses[0]?.employer || 'Entreprise';
const campaignName = webhookBody.campaign_name || nestedBody.campaign_name || input.campaign_name || (campaignId ? `Campagne ${campaignId}` : 'Campagne RPS');
const clientEmail = nestedBody.client_email || webhookBody.client_email || webhookBody.user_email || input.user_email || input.client_email || input.clientEmail || '';

const questionKeys = [...new Set(responses.flatMap((row) => Object.keys(row || {}).filter((key) => /^Q\d+$/.test(key))))]
  .sort((a, b) => Number(a.slice(1)) - Number(b.slice(1)));

const formattedForAI = responses.length > 0
  ? responses.map((row, index) => {
      const identity = row['Nom et Prenom'] || row['Nom et Pr\u00e9nom(s)'] || row.nom || row.name || `Repondant ${index + 1}`;
      const header = [`Repondant ${index + 1}`, identity, row.Fonction || row.fonction, row.Email || row.email].filter(Boolean).join(' - ');
      const answers = questionKeys.map((key) => `${key}: ${row[key] ?? ''}`).join('\n');
      return `${header}\n${answers}`;
    }).join('\n\n---\n\n')
  : 'Aucune reponse exploitable recue.';

return [{
  json: {
    campaignInfo: {
      entreprise: companyName,
      campagne: campaignName,
      total_repondants: responses.length,
      campaign_id: campaignId,
      client_email: clientEmail
    },
    openAnswers: responses,
    formattedForAI
  }
}];

// Construire le rapport final formaté
const analysis = $input.first().json.output || $input.first().json.text || $input.first().json.response || Object.values($input.first().json)[0];const campaignInfo = $('Formater les donnees').first().json.campaignInfo;

const now = new Date();
const dateStr = now.toLocaleDateString('fr-CA', { year: 'numeric', month: 'long', day: 'numeric' });

const rapport = `
=================================================
RAPPORT D'ANALYSE RPS
=================================================
Entreprise    : ${campaignInfo.entreprise}
Campagne      : ${campaignInfo.campagne}
Date d'analyse: ${dateStr}
RÃ©pondants    : ${campaignInfo.total_repondants}
=================================================

${analysis}

=================================================
Rapport gÃ©nÃ©rÃ© automatiquement par la plateforme RPS
Confidentiel - Usage interne uniquement
=================================================
`.trim();

return [{
  json: {
    rapport,
    campaignInfo,
    subject: `Rapport RPS -  - ${campaignInfo.campagne}`,
    filename: `Rapport_RPS.replace(/\s+/g, '_')}_${now.toISOString().split('T')[0]}.txt`
  }
}];

