const payload = $input.first().json;
const campaigns = Array.isArray(payload.campaigns) ? payload.campaigns : [];
const participants = [];

for (const campaign of campaigns) {
  const campaignParticipants = Array.isArray(campaign.participants) ? campaign.participants : [];

  for (const participant of campaignParticipants) {
    participants.push({
      json: {
        ...participant,
        campaign_id: participant.campaign_id || campaign.campaign_id,
        campaign_name: participant.campaign_name || campaign.campaign_name,
        company_name: participant.company_name || campaign.company_name,
      },
    });
  }
}

return participants;

const env = typeof $env === 'undefined' ? {} : $env;
const minDays = Number(env.REMINDER_MIN_DAYS || 6);
const maxCount = Number(env.REMINDER_MAX_COUNT || 2);
const now = Date.now();
const result = [];

for (const item of $input.all()) {
  const participant = item.json;

  if (!participant.email || participant.status === 'completed') {
    continue;
  }

  const reminderCount = Number(participant.reminder_count || 0);
  if (Number.isFinite(maxCount) && maxCount >= 0 && reminderCount >= maxCount) {
    continue;
  }

  const invitationDate = participant.invitation_sent_at ? new Date(participant.invitation_sent_at) : null;
  if (!invitationDate || Number.isNaN(invitationDate.getTime())) {
    continue;
  }

  const daysSinceInvitation = Math.floor((now - invitationDate.getTime()) / (1000 * 60 * 60 * 24));
  if (daysSinceInvitation < minDays) {
    continue;
  }

  result.push({
    json: {
      ...participant,
      jours_depuis_envoi: daysSinceInvitation,
      eligible_relance: true,
    },
  });
}

return result;

const participant = $('Calculer 6 jours').item.json;
const reminderResult = $input.first().json;
console.log(`Relance envoyee a ${participant.nom} (${participant.email}) - ${participant.jours_depuis_envoi} jours depuis l'invitation`);

return [{
  json: {
    status: 'relance_envoyee',
    participant_id: participant.participant_id,
    nom: participant.nom,
    email: participant.email,
    jours_depuis_envoi: participant.jours_depuis_envoi,
    reminder_marked: reminderResult.updated ?? true,
    timestamp: new Date().toISOString()
  }
}];

// Log de confirmation
const info = $('Construire le rapport').first().json.campaignInfo;
console.log(`âœ… Rapport RPS gÃ©nÃ©rÃ© et envoyÃ© pour ${info.entreprise} - ${info.campagne}`);
return [{ json: { status: 'success', message: `Rapport envoyÃ© pour ${info.entreprise}`, timestamp: new Date().toISOString() } }];

